      const checkOutResult0 = await interpret(pessimisticLockHandler.checkOut({ resource: {"type":"variable","name":"r"}, holder: {"type":"variable","name":"h"}, duration: {"type":"variable","name":"_"}, reason: {"type":"variable","name":"_"} }), storage);
